// Normalize incoming telemetry data from various fleet systems
// into a unified schema

const inputData = $input.item.json;

// Initialize normalized telemetry object with standard fields
const normalizedTelemetry = {
  vehicleId: inputData.vehicleId || inputData.vehicle_id || inputData.VehicleID || inputData.id || null,
  timestamp: inputData.timestamp || inputData.time || inputData.eventTime || new Date().toISOString(),
  location: {
    lat: inputData.latitude || inputData.lat || inputData.location?.lat || inputData.gps?.latitude || null,
    lng: inputData.longitude || inputData.lng || inputData.location?.lng || inputData.gps?.longitude || null
  },
  speed: inputData.speed || inputData.velocity || inputData.speedKmh || inputData.speed_kmh || 0,
  fuelLevel: inputData.fuelLevel || inputData.fuel_level || inputData.fuel || inputData.fuelPercent || null,
  engineStatus: inputData.engineStatus || inputData.engine_status || inputData.status || inputData.engineState || 'unknown',
  driverId: inputData.driverId || inputData.driver_id || inputData.DriverID || inputData.operator || null,
  odometer: inputData.odometer || inputData.mileage || inputData.totalDistance || inputData.odometer_km || 0,
  temperature: inputData.temperature || inputData.temp || inputData.engineTemp || inputData.engine_temperature || null,
  eventType: inputData.eventType || inputData.event_type || inputData.type || inputData.event || 'telemetry_update'
};

// Return normalized data
return normalizedTelemetry;

// Validate telemetry data quality
const item = $input.item.json;

// Initialize validation result
const validationErrors = [];
let isValid = true;

// Check for required fields
if (!item.vehicleId) {
  validationErrors.push('Missing required field: vehicleId');
  isValid = false;
}

if (!item.timestamp) {
  validationErrors.push('Missing required field: timestamp');
  isValid = false;
}

if (!item.location) {
  validationErrors.push('Missing required field: location');
  isValid = false;
}

// Validate data types
if (item.vehicleId && typeof item.vehicleId !== 'string') {
  validationErrors.push('Invalid data type for vehicleId: expected string');
  isValid = false;
}

if (item.timestamp && isNaN(Date.parse(item.timestamp))) {
  validationErrors.push('Invalid data type for timestamp: expected valid date');
  isValid = false;
}

if (item.location && typeof item.location !== 'object') {
  validationErrors.push('Invalid data type for location: expected object');
  isValid = false;
}

// Check for reasonable value ranges
if (item.speed !== undefined) {
  const speed = parseFloat(item.speed);
  if (isNaN(speed) || speed < 0 || speed > 200) {
    validationErrors.push('Speed out of valid range (0-200): ' + item.speed);
    isValid = false;
  }
}

if (item.fuelLevel !== undefined) {
  const fuelLevel = parseFloat(item.fuelLevel);
  if (isNaN(fuelLevel) || fuelLevel < 0 || fuelLevel > 100) {
    validationErrors.push('Fuel level out of valid range (0-100): ' + item.fuelLevel);
    isValid = false;
  }
}

// Return item with validation results
return {
  ...item,
  isValid: isValid,
  validationErrors: validationErrors.length > 0 ? validationErrors : undefined
};

