// Apply Business Rules to Fleet Telemetry Data

// Get workflow configuration if available
const config = $('Workflow Configuration').first()?.json || {};

// Get current item data
const item = $input.item.json;

// Initialize business rules validation
let businessRulesPassed = true;
let priority = 0;
const ruleViolations = [];

// 1. Check Dispatch Capacity Limits
const maxDispatchCapacity = config.maxDispatchCapacity || 100;
const currentDispatchCount = item.currentDispatchCount || 0;

if (currentDispatchCount >= maxDispatchCapacity) {
  businessRulesPassed = false;
  ruleViolations.push('Dispatch capacity limit exceeded');
  priority += 50; // High priority for capacity issues
}

// 2. Validate DOT Compliance Regulations
const dotCompliant = item.dotCompliant !== false; // Default to true if not specified
const vehicleInspectionCurrent = item.vehicleInspectionCurrent !== false;

if (!dotCompliant || !vehicleInspectionCurrent) {
  businessRulesPassed = false;
  ruleViolations.push('DOT compliance violation detected');
  priority += 75; // Very high priority for compliance
}

// 3. Enforce Driver Hours of Service Limits
const maxDriverHours = config.maxDriverHoursOfService || 11; // DOT standard
const driverHoursWorked = item.driverHoursWorked || 0;
const driverRestHours = item.driverRestHours || 0;

if (driverHoursWorked >= maxDriverHours) {
  businessRulesPassed = false;
  ruleViolations.push('Driver hours of service limit exceeded');
  priority += 100; // Critical priority for safety
}

if (driverRestHours < 10 && driverHoursWorked > 8) {
  ruleViolations.push('Insufficient driver rest period');
  priority += 60;
}

// 4. Calculate Priority Score Based on Delivery Windows
const deliveryDeadline = item.deliveryDeadline ? new Date(item.deliveryDeadline) : null;
const currentTime = new Date();

if (deliveryDeadline) {
  const hoursUntilDeadline = (deliveryDeadline - currentTime) / (1000 * 60 * 60);

  if (hoursUntilDeadline < 2) {
    priority += 90; // Urgent delivery
  } else if (hoursUntilDeadline < 4) {
    priority += 60; // High priority
  } else if (hoursUntilDeadline < 8) {
    priority += 30; // Medium priority
  } else {
    priority += 10; // Normal priority
  }

  if (hoursUntilDeadline < 0) {
    businessRulesPassed = false;
    ruleViolations.push('Delivery deadline already passed');
    priority += 100;
  }
}

// 5. Apply Rate Limiting for API Calls
const apiCallTimestamp = Date.now();
const lastApiCall = item.lastApiCallTimestamp || 0;
const minApiCallInterval = config.minApiCallIntervalMs || 1000; // 1 second default

if (apiCallTimestamp - lastApiCall < minApiCallInterval) {
  ruleViolations.push('API rate limit - call too frequent');
  // Don't fail business rules, but log the violation
}

// 6. Additional Business Logic
if (item.anomalyDetected === true) {
  priority += 40; // Increase priority for anomalies
}

if (item.severity === 'critical') {
  priority += 80;
} else if (item.severity === 'high') {
  priority += 50;
} else if (item.severity === 'medium') {
  priority += 25;
}

// Cap priority at 100
priority = Math.min(priority, 100);

// Return enriched data with business rules results
return {
  ...item,
  businessRulesPassed,
  priority,
  ruleViolations,
  businessRulesAppliedAt: new Date().toISOString(),
  lastApiCallTimestamp: apiCallTimestamp
};

// Trigger Re-routing Action
// Identify alternative vehicles, calculate new routes, update dispatch system

const item = $input.item.json;

// Extract incident details
const incidentId = item.incidentId || item.id || 'INC-' + Date.now();
const affectedVehicleId = item.vehicleId || item.vehicle_id;
const location = item.location || { lat: 0, lon: 0 };
const severity = item.severity || 'medium';
const reason = item.reason || item.anomaly_type || 'route_optimization_required';

// Identify alternative vehicles
// In production, this would query a vehicle availability database
const availableVehicles = [
  { id: 'VEH-ALT-001', distance: 2.5, eta: 15, capacity: 'high' },
  { id: 'VEH-ALT-002', distance: 3.8, eta: 22, capacity: 'medium' },
  { id: 'VEH-ALT-003', distance: 1.9, eta: 12, capacity: 'high' }
];

// Select best alternative vehicle (closest with adequate capacity)
const selectedVehicle = availableVehicles.sort((a, b) => a.eta - b.eta)[0];

// Calculate new route
const newRoute = {
  vehicleId: selectedVehicle.id,
  origin: selectedVehicle.currentLocation || { lat: location.lat + 0.01, lon: location.lon + 0.01 },
  destination: location,
  estimatedDistance: selectedVehicle.distance,
  estimatedDuration: selectedVehicle.eta,
  waypoints: [
    { lat: location.lat + 0.005, lon: location.lon + 0.005, order: 1 },
    { lat: location.lat + 0.002, lon: location.lon + 0.002, order: 2 }
  ]
};

// Update dispatch system (simulated)
const dispatchUpdate = {
  action: 'reassign',
  originalVehicle: affectedVehicleId,
  newVehicle: selectedVehicle.id,
  incidentId: incidentId,
  priority: severity === 'critical' ? 'urgent' : 'normal',
  status: 'dispatched',
  updatedAt: new Date().toISOString()
};

// Log re-routing event
const reroutingLog = {
  eventId: 'REROUTE-' + Date.now(),
  timestamp: new Date().toISOString(),
  incidentId: incidentId,
  reason: reason,
  originalAssignment: {
    vehicleId: affectedVehicleId,
    status: 'reassigned'
  },
  newAssignment: {
    vehicleId: selectedVehicle.id,
    eta: selectedVehicle.eta,
    route: newRoute
  },
  dispatchUpdate: dispatchUpdate,
  metadata: {
    alternativesConsidered: availableVehicles.length,
    selectionCriteria: 'shortest_eta',
    severity: severity
  }
};

// Return re-routing confirmation
const confirmation = {
  success: true,
  reroutingId: reroutingLog.eventId,
  incidentId: incidentId,
  newVehicleId: selectedVehicle.id,
  updatedETA: selectedVehicle.eta,
  estimatedArrival: new Date(Date.now() + selectedVehicle.eta * 60000).toISOString(),
  route: newRoute,
  log: reroutingLog,
  message: `Successfully re-routed incident ${incidentId} to vehicle ${selectedVehicle.id} with ETA of ${selectedVehicle.eta} minutes`
};

return {
  json: {
    ...item,
    reroutingConfirmation: confirmation,
    reroutingLog: reroutingLog,
    newVehicleId: selectedVehicle.id,
    updatedETA: selectedVehicle.eta,
    reroutingTimestamp: new Date().toISOString()
  }
};
